func serviceConfigFromDDxEndpoints(workDir string) (agentlib.ServiceConfig, error) {
	cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
	if err != nil {
		return nil, err
	}
	if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
